module shift_register(D, rst, reset, load, shift, Q);
    input [7:0] D;
    input rst, reset, load, shift;
    output reg [7:0] Q;

    always @(posedge rst or posedge reset) begin
        if (reset)
            Q <= 8'b0;
        else if (load)
            Q <= D;
        else if (shift)
            Q <= {Q[6:0], 1'b0};
    end
endmodule
